func TestAptosVectors(t *testing.T) {
	acc, err := NewAccountFromMnemonic(testMnemonic, testPath)
	if err != nil {
		t.Fatal(err)
	}
	if acc.Address() != testSender {
		t.Fatalf("sender mismatch: got %s want %s", acc.Address(), testSender)
	}
	if acc.PublicKeyHex() != testPub {
		t.Fatalf("public key mismatch: got %s want %s", acc.PublicKeyHex(), testPub)
	}

	for _, v := range aptVectors() {
		t.Run(v.name, func(t *testing.T) {
			b := NewTxBuilder(&Ingredient{
				TxType:           v.txType,
				ContractAddress:  v.contract,
				Sender:           testSender,
				SenderPublicKey:  testPub,
				Recipient:        testRecip,
				Amount:           v.amount,
				Nonce:            "7",
				GasPrice:         "100",
				GasLimit:         "2000",
				LedgerInfoParams: &LedgerInfoParams{ExpirationTimestamp: "1700000000", ChainId: "1"},
			})
			if err := b.Build(); err != nil {
				t.Fatalf("build: %v", err)
			}
			if b.GetUnsignedHex() != v.unsigned {
				t.Fatalf("unsigned mismatch:\n got %s\nwant %s", b.GetUnsignedHex(), v.unsigned)
			}
			sig, err := b.Sign(acc.PrivateKey())
			if err != nil {
				t.Fatalf("sign: %v", err)
			}
			if sig != v.signature {
				t.Fatalf("signature mismatch:\n got %s\nwant %s", sig, v.signature)
			}
			signed, err := b.ConcatSignature(sig, false)
			if err != nil {
				t.Fatalf("concat: %v", err)
			}
			if signed != v.signed {
				t.Fatalf("signed mismatch:\n got %s\nwant %s", signed, v.signed)
			}
			if b.GetTxHash() != v.txHash {
				t.Fatalf("txHash mismatch: got %s want %s", b.GetTxHash(), v.txHash)
			}
		})
	}
}
